-- 014_content_catalog: контент публичных разделов «Аналитика дочек» и «Карта проектов»
-- переносится из захардкоженных фронтенд-массивов в БД, чтобы им можно было
-- управлять из админ-кабинета (требование жюри по администрируемости портала).

-- ─── Аналитические материалы дочерних организаций ────────────────────────────
CREATE TABLE analytics_materials (
    id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    title         VARCHAR(500) NOT NULL,
    description   TEXT,
    org           VARCHAR(255),            -- дочерняя организация
    material_type VARCHAR(120),            -- Исследование / Дашборд / Годовой отчёт / …
    period        VARCHAR(60),             -- '2025', 'Q1 2026', '2025–2026'
    source        VARCHAR(255),            -- источник (домен/подразделение)
    url           VARCHAR(1000),           -- ссылка/embed URL
    format        VARCHAR(20) NOT NULL DEFAULT 'web',  -- 'web' | 'pdf' | 'embed'
    updated_date  VARCHAR(40),             -- дата обновления, как в исходных данных
    sort_order    INT NOT NULL DEFAULT 0,
    created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_analytics_materials_sort ON analytics_materials(sort_order, created_at);

-- ─── Проекты на карте (профинансированы дочками Байтерека) ────────────────────
CREATE TABLE map_projects (
    id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name        VARCHAR(500) NOT NULL,
    org         VARCHAR(255),
    region      VARCHAR(120),
    city        VARCHAR(120),
    industry    VARCHAR(120),
    status      VARCHAR(60),
    amount      NUMERIC NOT NULL DEFAULT 0,   -- сумма финансирования, млн ₸
    period      VARCHAR(60),                  -- '2024–2026', '2025'
    description TEXT,
    lat         DOUBLE PRECISION,             -- NULL → фронт берёт центр региона
    lng         DOUBLE PRECISION,
    sort_order  INT NOT NULL DEFAULT 0,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_map_projects_sort ON map_projects(sort_order, created_at);

-- ─── Сиды: аналитические материалы (перенос из MATERIALS) ─────────────────────

-- ─── Сиды: проекты на карте (перенос из RAW_PROJECTS) ─────────────────────────
-- lat/lng NULL — координаты вычисляются на фронте из центра региона (REGION_COORDS)
-- с детерминированным разбросом по sort_order (полное соответствие прежнему поведению).
